// optional import of sdk modules
import { execution } from "@dynatrace-sdk/automation-utils";
import { queryExecutionClient } from "@dynatrace-sdk/client-query";

export default async function () {
  // loop through result of ec2_describe_security_groups_1'
  const ex = await execution();
  const result = await ex.result("ec2_describe_security_groups_1");
  const noncompliant_sg = [];
  const dt_regions = [];
  for (let results of result) {
    for (let sg of results.SecurityGroups) {
      console.log("Security Group Name: " + sg.GroupName);
      console.log("Security Group id: " + sg.GroupId);
      let endstring: number = sg.SecurityGroupArn.indexOf(":", 13);
      let region = sg.SecurityGroupArn.substring(12, endstring);
      sg["region"] = region;

      const res = await queryExecutionClient.queryExecute({
        body: {
          query:
            'fetch dt.entity.aws_availability_zone | filter matchesPhrase(entity.name, "' +
            region +
            '*") |  fields id',
          requestTimeoutMilliseconds: 45 * 1000,
        },
      });
      for (let ids of res.result.records) {
        console.log(ids.id);
        dt_regions.push(ids.id);

      }

      const uniqueArray = [...new Set(dt_regions)];

      sg["dt_region_ids"] = uniqueArray;
      for (let ingress_permission of sg.IpPermissions) {
        //console.log(ingress_permission.IpRanges)
        for (let range of ingress_permission.IpRanges) {
          //check if ip is open to the internet "0.0.0.0/0"
          console.log("Ip Range: " + range.CidrIp);
          if (range.CidrIp == "0.0.0.0/0")
            //sg.push("region": ""+region+"")
            noncompliant_sg.push(sg);
        }
      }
    }
  }

  return noncompliant_sg;
}
